    /**
     * Id
     */
    id?: string | null;
    /**
     * Name
     */
    name: string;
    /**
     * Description
     */
    description?: string | null;
    /**
     * Visibility
     */
    visibility?: string;
    /**
     * Payment Method
     */
    payment_method?: string;
    /**
     * Purchasable By
     */
    purchasable_by?: string;
    /**
     * Restrict Visibility To Linked Invitations
     *
     * When True and visibility=PRIVATE, only users whose invitation links to this tier can see it.
     */
    restrict_visibility_to_linked_invitations?: boolean;
    /**
     * Restrict Purchase To Linked Invitations
     *
     * When True and purchasable_by includes INVITED, only users whose invitation links to this tier can purchase.
     */
    restrict_purchase_to_linked_invitations?: boolean;
    /**
     * Price
     */
    price?: string;
    /**
     * Price Type
     *
     * Whether this tier has a fixed price or allows pay-what-you-can pricing
     */
    price_type?: string;
    /**
     * Pwyc Min
     *
     * Minimum amount for pay-what-you-can pricing
     */
    pwyc_min?: string;
    /**
     * Pwyc Max
     *
     * Maximum amount for pay-what-you-can pricing (optional)
     */
    pwyc_max?: string | null;
    /**
     * Currency
     *
     * ISO 4217 currency code
     */
    currency?: string;
    /**
     * Sales Start At
     *
     * When ticket sales begin for this tier
     */
    sales_start_at?: string | null;
    /**
     * Sales End At
     *
     * When ticket sales end for this tier
     */
    sales_end_at?: string | null;
    /**
     * Created At
     */
    created_at: string;
    /**
     * Updated At
     */
    updated_at: string;
    /**
     * Total Quantity
     */
    total_quantity?: number | null;
    /**
     * Quantity Sold
     */
    quantity_sold?: number;
    /**
     * Manual Payment Instructions
     */
    manual_payment_instructions?: string | null;
    /**
     * Display Order
     */
    display_order?: number;
    /**
     * Allow User Cancellation
     *
     * When True, ticket holders can cancel their own tickets under this tier's refund policy.
     */
